<?php declare(strict_types=1);
namespace App\Services;
final class StreamPreflightService {
    public function validate(array $channel,array $videos,array $settings):void { $upload=config('settings.upload_directory');$logs=config('settings.log_directory');if(!$videos)throw new \RuntimeException('Playlist contains no videos.');if(!is_dir($upload)||!is_readable($upload))throw new \RuntimeException('Upload directory is not readable.');if(!is_dir($logs)||!is_writable($logs))throw new \RuntimeException('Log directory is not writable.');if(!is_file($settings['ffmpeg_path'])||!is_executable($settings['ffmpeg_path']))throw new \RuntimeException('FFmpeg executable is unavailable.');if(!is_file($settings['ytdlp_path'])||!is_executable($settings['ytdlp_path']))throw new \RuntimeException('yt-dlp executable is unavailable.');if(!filter_var($channel['rtmp_url'],FILTER_VALIDATE_URL)||trim($channel['stream_key'])==='')throw new \RuntimeException('Channel RTMP configuration is invalid.');if(!preg_match('/^\d{2,5}k$/i',$settings['default_bitrate'])||!preg_match('/^\d{2,4}x\d{2,4}$/',$settings['default_resolution']))throw new \RuntimeException('Stream bitrate or resolution is invalid.');foreach($videos as $video)if(!is_file($upload.'/'.$video['filename']))throw new \RuntimeException('Playlist video is missing: '.$video['title']);if((disk_free_space($upload)?:0)<config('stream.minimum_free_disk_bytes'))throw new \RuntimeException('Insufficient disk space for streaming.'); }
}
